const fs = require('fs');
const path = require('path');

// Monkey-patch readFileSync to throw on .env files to simulate a permission error
const originalReadFileSync = fs.readFileSync;
fs.readFileSync = function(...args) {
  const filePath = typeof args[0] === 'string' ? args[0] : args[0].toString();
  if (filePath.endsWith('.env')) {
    console.log('[PRELOAD] .env file read attempted, throwing EACCES to simulate permission error');
    const err = new Error('EACCES: permission denied');
    err.code = 'EACCES';
    err.errno = -13;
    err.syscall = 'open';
    err.path = filePath;
    throw err;
  }
  return originalReadFileSync.apply(this, args);
};

// After loadConfig runs, check if the .env values were loaded
const origModuleLoad = require('module')._load;
require('module')._load = function(request, parent, isMain) {
  const exports = origModuleLoad.apply(this, arguments);
  if (request === './index.js' || request === '/pkg/index.js') {
    console.log('[PRELOAD] Detected loadConfig module load');
    const config = exports.loadConfig({ prefix: 'MYAPP_' });
    console.log('[PRELOAD] Config result:', JSON.stringify(config, null, 2));
    // Check if .env values made it in
    if (config.db_host === 'should_override') {
      console.log('[PRELOAD] OUTCOME: .env silently parsed successfully (expected)');
    } else {
      console.log('[PRELOAD] OUTCOME: .env values MISSING - empty catch swallowed the error!');
      console.log('[PRELOAD] DESTRUCTIVE: User expected .env to override but got no error or warning');
    }
  }
  return exports;
};
